import React, { useState, useEffect } from "react";
import { BrowserRouter, Routes, Route, NavLink, useLocation } from "react-router-dom";
import { DataProvider, useData } from "./lib/DataContext";
import Dashboard from "./pages/Dashboard";
import WorkOrders from "./pages/WorkOrders";
import Equipment from "./pages/Equipment";
import TimeTracking from "./pages/TimeTracking";
import Reports from "./pages/Reports";
import Parts from "./pages/Parts";
import { getAuthToken, setAuthToken, initGoogleAuth } from "./lib/sheets";
import {
  LayoutDashboard, ClipboardList, Wrench,
  Timer, BarChart2, Settings, Package, LogIn, LogOut, CheckCircle
} from "lucide-react";
import "./index.css";

const NAV = [
  { to: "/",          icon: LayoutDashboard, label: "Dashboard" },
  { to: "/orders",    icon: ClipboardList,   label: "Orders" },
  { to: "/equipment", icon: Wrench,          label: "Equipment" },
  { to: "/time",      icon: Timer,           label: "Time" },
  { to: "/parts",     icon: Package,         label: "Parts" },
  { to: "/reports",   icon: BarChart2,       label: "Reports" },
];

function Shell({ children }) {
  const data    = useData();
  const isDemo  = data?.isDemo ?? true;
  const location = useLocation();
  const [authed, setAuthed]       = useState(!!getAuthToken());
  const [signing, setSigning]     = useState(false);

  // Auto-trigger sign in on first load if not demo and not authed
  useEffect(() => {
    if (!isDemo && !authed) {
      handleSignIn();
    }
  }, [isDemo]);

  const handleSignIn = () => {
    if (!window.google) {
      alert("Google Identity Services not loaded yet. Please wait a moment and try again.");
      return;
    }
    setSigning(true);
    initGoogleAuth((token) => {
      setSigning(false);
      if (token) {
        setAuthed(true);
      }
    });
  };

  const handleSignOut = () => {
    sessionStorage.removeItem("gapi_token");
    setAuthed(false);
  };

  return (
    <div className="app-shell">
      {/* Topbar */}
      <header className="topbar">
        <div className="topbar-logo">
          <Wrench size={20} />
          MechTrack
        </div>
        <span className="topbar-tag">v1.0</span>
        {isDemo && <span className="topbar-demo-badge">DEMO MODE</span>}
        <div className="topbar-spacer" />

        {/* Auth button — only show when not demo */}
        {!isDemo && (
          authed ? (
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <CheckCircle size={14} color="var(--success)" />
              <span style={{ fontSize: 12, color: "var(--success)", fontFamily: "var(--font-mono)" }}>
                Connected
              </span>
              <button
                className="btn btn-ghost btn-sm"
                onClick={handleSignOut}
                style={{ marginLeft: 4 }}
              >
                <LogOut size={13} /> Sign out
              </button>
            </div>
          ) : (
            <button
              className="btn btn-primary btn-sm"
              onClick={handleSignIn}
              disabled={signing}
            >
              <LogIn size={13} />
              {signing ? "Signing in..." : "Sign in with Google"}
            </button>
          )
        )}

        <div className="topbar-user" style={{ marginLeft: 12 }}>
          <div className="topbar-avatar">MT</div>
          <span style={{ fontSize: 13, color: "var(--text2)" }}>
            {isDemo ? "Demo User" : "MechTrack"}
          </span>
        </div>
      </header>

      {/* Sign-in banner — shown when connected but not authed */}
      {!isDemo && !authed && (
        <div style={{
          gridColumn: "1 / -1",
          background: "rgba(224,83,83,0.1)",
          border: "1px solid rgba(224,83,83,0.3)",
          padding: "10px 24px",
          display: "flex",
          alignItems: "center",
          gap: 12,
          fontSize: 13,
        }}>
          <span style={{ color: "var(--danger)" }}>⚠ Not signed in — you can view data but cannot save new records.</span>
          <button className="btn btn-primary btn-sm" onClick={handleSignIn} disabled={signing}>
            <LogIn size={13} /> {signing ? "Signing in..." : "Sign in with Google to save data"}
          </button>
        </div>
      )}

      {/* Desktop sidebar */}
      <aside className="sidebar">
        <div className="sidebar-section">Navigation</div>
        {NAV.map(({ to, icon: Icon, label }) => (
          <NavLink key={to} to={to} end={to === "/"} className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>
            <Icon size={16} />
            {label}
          </NavLink>
        ))}
        <div className="sidebar-section" style={{ marginTop: "auto" }}>System</div>
        <NavLink to="/settings" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>
          <Settings size={16} /> Settings
        </NavLink>
      </aside>

      {/* Page */}
      <main className="main-content">
        {children}
      </main>

      {/* Mobile bottom nav */}
      <nav className="mobile-nav">
        {NAV.map(({ to, icon: Icon, label }) => (
          <NavLink key={to} to={to} end={to === "/"} className={({ isActive }) => isActive ? "active" : ""}>
            <Icon size={20} />
            {label}
          </NavLink>
        ))}
      </nav>
    </div>
  );
}

